#include<bits/stdc++.h>
using namespace std;
vector<int>v[1000];
int fa[1000];
int depth[1000];
void dfs(int x, int d){
	depth[x] = d;
	for(int i = 0; i < v[x].size(); i++){
		dfs(v[x][i], d + 1);
	}
	return;
}

int lca(int u, int v){
    int cnt1 = 0, cnt2 = 0;
    while(depth[u] > depth[v]){
        u = fa[u];
        cnt1++;
    }
    while(depth[v] > depth[u]){
        v = fa[v];
        cnt2++;
    }
    while(u != v){
        u = fa[u];
        v = fa[v];
        cnt1++;
        cnt2++;
    }

    return 2 * cnt1 + cnt2;
}
int main()
{
	int n ;
	cin >> n;
	for(int i = 1; i < n; i++){
		int u, V;
		cin >> u >> V;
		v[u].push_back(V);
		fa[V] = u;
	}
	int u, V;
	dfs(1, 1);
	cin >> u >> V;
	int ans = lca(u, V);
	sort(depth + 1, depth + n + 1);
	int cnt = 1, maxw = 0, maxd = 0;;
	for(int i = 1; i <= n; i++){
		if(depth[i] != depth[i + 1]){
			maxw = max(maxw, cnt);
			cnt = 0;
		}
		maxd = max(maxd, depth[i]);
		cnt++;
	}
	cout << maxd << "\n" << maxw << "\n";


	cout << ans;
 }
